UPDATE federated_billing_rule
rule_name = #{ruleName}, price_per_query = #{pricePerQuery}, price_per_hit = #{pricePerHit}, min_charge = #{minCharge}, enable_discount = #{enableDiscount}, discount_threshold = #{discountThreshold}, discount_rate = #{discountRate}, is_active = #{isActive}, effective_from = #{effectiveFrom}, effective_to = #{effectiveTo},
WHERE id = #{id}

mapper.select:
SELECT * FROM federated_billing_rule

    AND billing_type = #{billingType}
    AND is_active = #{isActive}

ORDER BY created_at DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*) FROM federated_billing_rule

    AND billing_type = #{billingType}
    AND is_active = #{isActive}

SELECT * FROM federated_billing_record

    AND requester_organ_id = #{requesterOrganId}
    AND billing_type = #{billingType}
    AND charge_status = #{chargeStatus}

ORDER BY billing_time DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*) FROM federated_billing_record

    AND requester_organ_id = #{requesterOrganId}
    AND billing_type = #{billingType}
    AND charge_status = #{chargeStatus}

SELECT COUNT(*) total_count, COALESCE(SUM(total_charge), 0) total_charge,
       COALESCE(AVG(total_charge), 0) avg_charge
FROM federated_billing_record

    AND requester_organ_id = #{requesterOrganId}
    AND billing_time >= #{startDate}
    AND billing_time <= #{endDate}

SELECT DATE(billing_time) date, COUNT(*) count, COALESCE(SUM(total_charge), 0) total
FROM federated_billing_record

    AND billing_time >= #{startDate}
    AND billing_time <= #{endDate}

GROUP BY DATE(billing_time)
ORDER BY date
